import { get } from "mongoose";
import { PRODUCT_URL } from "../constant";
import { apiSlice } from "./apiSlice";

export const productApiSlice = apiSlice.injectEndpoint({
  endpoint: (builder) => ({
    getproducts: builder.query({
      query: () => ({
        url: PRODUCT_URL,
      }),
      keepUnusedData: 5,
    }),
  }),
});

export const { useGetProductQuary } = productApiSlice;
